from collections import Counter

def solve(grid):
    grid = np.array(grid)
    H, W = grid.shape

    # Find the split
    template = None
    content = None
    border_color = None
    hole_color = None

    def check_split(template_region, content_region, direction, side, pos):
        t_colors = set(template_region.flatten().tolist())
        if len(t_colors) != 2:
            return None
        c_colors = set(content_region.flatten().tolist())
        if len(c_colors) <= 2:
            return None

        c_counts = Counter(content_region.flatten().tolist())
        hc = c_counts.most_common(1)[0][0]
        if hc not in t_colors:
            return None
        bc = (t_colors - {hc}).pop()

        # Check boundary edge
        if direction == 'h':
            edge = template_region[-1] if side == 'top' else template_region[0]
        else:
            edge = template_region[:, -1] if side == 'left' else template_region[:, 0]

        if set(edge.tolist()) == {bc}:
            return (bc, hc)
        return None

    # Try all splits, prefer the one with valid border
    for r in range(2, H-1):
        res = check_split(grid[:r], grid[r:], 'h', 'top', r)
        if res:
            template, content = grid[:r].copy(), grid[r:].copy()
            border_color, hole_color = res
            break
        res = check_split(grid[r:], grid[:r], 'h', 'bot', r)
        if res:
            template, content = grid[r:].copy(), grid[:r].copy()
            border_color, hole_color = res
            break

    if template is None:
        for c in range(2, W-1):
            res = check_split(grid[:, :c], grid[:, c:], 'v', 'left', c)
            if res:
                template, content = grid[:, :c].copy(), grid[:, c:].copy()
                border_color, hole_color = res
                break
            res = check_split(grid[:, c:], grid[:, :c], 'v', 'right', c)
            if res:
                template, content = grid[:, c:].copy(), grid[:, :c].copy()
                border_color, hole_color = res
                break

    # Extract pieces from content
    mask = (content != hole_color).astype(int)
    labeled, num_features = scipy_label(mask)

    pieces = []
    for i in range(1, num_features + 1):
        coords = np.argwhere(labeled == i)
        r_min, c_min = coords.min(axis=0)
        r_max, c_max = coords.max(axis=0)
        piece = content[r_min:r_max+1, c_min:c_max+1].copy()
        pieces.append(piece)

    # Find hole positions
    hole_cells = set()
    tH, tW = template.shape
    for r in range(tH):
        for c in range(tW):
            if template[r, c] == hole_color:
                hole_cells.add((r, c))

    # Backtracking to tile the hole
    output = template.copy()
    filled = set()
    used = [False] * len(pieces)

    def get_first_unfilled():
        for r in range(tH):
            for c in range(tW):
                if (r, c) in hole_cells and (r, c) not in filled:
                    return (r, c)
        return None

    def try_place(piece_idx, top_r, top_c):
        """Try to place piece at (top_r, top_c) as top-left corner."""
        piece = pieces[piece_idx]
        pH, pW = piece.shape
        cells = []
        for pr in range(pH):
            for pc in range(pW):
                r, c = top_r + pr, top_c + pc
                if (r, c) not in hole_cells or (r, c) in filled:
                    return None
                cells.append((r, c, piece[pr, pc]))
        return cells

    def backtrack():
        pos = get_first_unfilled()
        if pos is None:
            return True  # All filled!

        r, c = pos
        for i in range(len(pieces)):
            if used[i]:
                continue
            cells = try_place(i, r, c)
            if cells is not None:
                # Place the piece
                used[i] = True
                for cr, cc, cv in cells:
                    filled.add((cr, cc))
                    output[cr, cc] = cv

                if backtrack():
                    return True

                # Undo
                used[i] = False
                for cr, cc, cv in cells:
                    filled.discard((cr, cc))
                    output[cr, cc] = hole_color

        return False

    success = backtrack()
    return output.tolist()

# Test on training examples
for i, s in enumerate(train_samples):
    result = solve(s['input'])
    expected = s['output']
    if result == expected:
        print(f"Train {i}: CORRECT")
    else:
