import numpy as np
from scipy.ndimage import label as scipy_label
from collections import Counter

def solve(grid):
    grid = np.array(grid)
    H, W = grid.shape

    template = content = None
    border_color = hole_color = None

    def check_and_set(t, co, direction, side):
        t_colors = set(t.flatten().tolist())
        if len(t_colors) != 2:
            return False
        c_colors = set(co.flatten().tolist())
        if len(c_colors) <= 2:
            return False
        c_counts = Counter(co.flatten().tolist())
        hc = c_counts.most_common(1)[0][0]
        if hc not in t_colors:
            return False
        bc = (t_colors - {hc}).pop()
        if direction == 'h':
            edge = t[-1] if side == 'top' else t[0]
        else:
            edge = t[:, -1] if side == 'left' else t[:, 0]
        if set(edge.tolist()) == {bc}:
            return (t.copy(), co.copy(), bc, hc)
        return False

    # Try horizontal splits
    for r in range(2, H-1):
        res = check_and_set(grid[:r], grid[r:], 'h', 'top')
        if res:
            template, content, border_color, hole_color = res
            break
        res = check_and_set(grid[r:], grid[:r], 'h', 'bot')
        if res:
            template, content, border_color, hole_color = res
            break

    if template is None:
        for c in range(2, W-1):
            res = check_and_set(grid[:, :c], grid[:, c:], 'v', 'left')
            if res:
                template, content, border_color, hole_color = res
                break
            res = check_and_set(grid[:, c:], grid[:, :c], 'v', 'right')
            if res:
                template, content, border_color, hole_color = res
                break

    # Extract pieces from content
    mask = (content != hole_color).astype(int)
    labeled, num_features = scipy_label(mask)

    pieces = []
    for i in range(1, num_features + 1):
        coords = np.argwhere(labeled == i)
        r_min, c_min = coords.min(axis=0)
        r_max, c_max = coords.max(axis=0)
        piece = content[r_min:r_max+1, c_min:c_max+1].copy()
        pieces.append(piece)

    # Find hole positions
    tH, tW = template.shape
    hole_cells = set()
    for r in range(tH):
        for c in range(tW):
            if template[r, c] == hole_color:
                hole_cells.add((r, c))

    # Backtracking to tile the hole
    output = template.copy()
    filled = set()
    used = [False] * len(pieces)

    # Precompute sorted hole cells for fast lookup
    sorted_holes = sorted(hole_cells)

    def get_first_unfilled():
        for pos in sorted_holes:
            if pos not in filled:
                return pos
        return None

    def try_place(piece_idx, top_r, top_c):
        piece = pieces[piece_idx]
        pH, pW = piece.shape
        cells = []
        for pr in range(pH):
            for pc in range(pW):
                r, c = top_r + pr, top_c + pc
                if (r, c) not in hole_cells or (r, c) in filled:
                    return None
                cells.append((r, c, int(piece[pr, pc])))
        return cells

    def backtrack():
        pos = get_first_unfilled()
        if pos is None:
            return True
        r, c = pos
        for i in range(len(pieces)):
            if used[i]:
                continue
            cells = try_place(i, r, c)
            if cells is not None:
                used[i] = True
                for cr, cc, cv in cells:
                    filled.add((cr, cc))
                    output[cr, cc] = cv
                if backtrack():
                    return True
                used[i] = False
                for cr, cc, cv in cells:
                    filled.discard((cr, cc))
                    output[cr, cc] = hole_color
        return False

    backtrack()
    return output.tolist()

